在项目目录下新建一个`test.html`，引用构建在项目目录下的`packages/vue/dist/vue.global.js`，在项目目录下执行`npm run dev`，写一个最简单 Vue 3.x 的 demo ，用浏览器打开可以直接运行，利用这个 demo ，我们构建好了 Vue 3.x 基本的运行环境，下面可以开始进行源码的调试了。

```html
<!DOCTYPE html>
<html>
<head>
    <title>vue-demo</title>
</head>
<body>
    <div id="app"></div>
    <script src="./packages/vue/dist/vue.global.js"></script>
    <script>
        const { createComponent, createApp, reactive, toRefs } = Vue;
        const component = createComponent({
            template: `
                <div>
                    {{ count }}
                    <button @click="addHandler">add</button>
                </div>
            `,
            setup(props) {
                const data = reactive({
                    count: 0,
                });
                const addHandler = () => {
                    data.count++;
                };
