大量占用`CPU`计算资源的任务称为`CPU-bound`的任务。

它的主要特点是`CPU`利用率较高，而不是`I/O`操作繁重。 让我们立即举一个例子上看看这些类型的任务在`Node.js`中的具体行为。

## 暴力求解子集求和问题
问题：类似于[Leetcode-40. Combination Sum II](https://leetcode.com/problems/combination-sum/description/)

> Given a collection of candidate numbers (C) and a target number (T), find all unique combinations in C where the candidate numbers sums to T.

> Each number in C may only be used once in the combination.

Example:

> For example, given candidate set `[10, 1, 2, 7, 6, 1, 5]` and target 8, A solution set is: 

```
[
  [1, 7],
  [1, 2, 5],
  [2, 6],
  [1, 1, 6]
]
```

暴力算法就是一个递归算法，这里主要探究`Node.js`上的解决方案，就不去探究算法本身。

## 构建Demo本身

我们使用`EventEmitter`来构建这个demo：

```javascript
"use strict";

const EventEmitter = require('events').EventEmitter;

class SubsetSum extends EventEmitter {
  /**
   * 构造函数，创建SubsetSum时调用
   * @param  {Number} sum 一个整数，期望的求和的整数
   * @param  {Array}  set 一个集合，被求解的集合
   */
  constructor(sum, set) {
    super();
    this.sum = sum;
    this.set = set;
    this.totalSubsets = 0;
  }

  /**
   * 递归地生成每一个可能的子集，而不把CPU控制权交还给事件循环。大量消耗CPU资源
   * @param  {Array} set    主集合
   * @param  {Array} subset 子集
   */
  _combine(set, subset) {
    for(let i = 0; i < set.length; i++) {
      let newSubset = subset.concat(set[i]);
      this._combine(set.slice(i + 1), newSubset);
      this._processSubset(newSubset);
    }
  }

  /**
   * 核对子集是否符合要求，一旦匹配到，则发出match事件
   * @param  {Array} subset 子集
   */
  _processSubset(subset) {
    console.log('Subset', ++this.totalSubsets, subset);
    const res = subset.reduce((prev, item) => (prev + item), 0);
    if(res == this.sum) {
      this.emit('match', subset);
    }
  }

  /**
   * 开始进行匹配，匹配完毕之后，发出end事件
   */
  start() {
    this._combine(this.set, []);
    this.emit('end');
  }
}

module.exports = SubsetSum;

```

为了说明`CPU-bound`任务造成的问题，创建一个`HTTP`服务器，对于网络请求作出响应：

```javascript
"use strict";

const http = require('http');
const SubsetSum = require('./subsetSum');

http.createServer((req, res) => {
  const url = require('url').parse(req.url, true);
  if(url.pathname === '/subsetSum') {
    const data = JSON.parse(url.query.data);
    res.writeHead(200);
    const subsetSum = new SubsetSum(url.query.sum, data);
    subsetSum.on('match', match => {
      res.write('Match: ' + JSON.stringify(match) + '\n');
    });
    subsetSum.on('end', () => res.end());
    subsetSum.start();
  } else {
    res.writeHead(200);
    res.end('I\m alive!\n');
  }
}).listen(8000, () => console.log('Started'));
```

由于`SubsetSum`实例使用事件返回结果，所以我们可以在算法生成后立即对匹配的结果使用`Stream`进行处理。另一个需要注意的细节是，每次我们的服务器都会返回`I'm alive!`，这样我们每次发送一个不同于`/subsetSum`的请求的时候。可以用来检查我们服务器是否挂掉了，这在稍后将会看到。

开始运行：

```bash
node app
```

一旦服务器启动，我们准备发送我们的第一个请求；让我们尝试发送一组17个随机数，服务器将会一直处于阻塞状态的计算中，那么将会导致服务器处理一段时间：

```bash
curl -G http://localhost:8000/subsetSum --data-urlencode "data=[116,119,101,101,-116,109,101,-105,-102,117,-115,-97,119,-116,-104,-105,115]"--data-urlencode "sum=0"
```

这是如果我们在第一个请求仍在运行的时候在另一个终端中尝试输入以下命令，我们将发现一个巨大的问题：

```bash
curl -G http://localhost:8000
```

## 方案一：使用setImmediate
现在我们来看看这个模式如何应用于子集求和算法。 我们所要做的只是稍微修改一下`subsetSum.js`模块。 为方便起见，我们将创建一个名为`subsetSumDefer.js`的新模块，将原始的`subsetSum`类的代码作为起点。
我们要做的第一个改变是添加一个名为`_combineInterleaved()`的新方法，它是我们正在实现的模式的核心：

```javascript
_combineInterleaved(set, subset) {
  this.runningCombine++;
  setImmediate(() => {
    this._combine(set, subset);
    if(--this.runningCombine === 0) {
      this.emit('end');
    }
  });
}
```

正如我们所看到的，我们所要做的只是使用`setImmediate()`调用原始的同步的`_combine()`方法。然而，现在的问题是因为该算法不再是同步的，我们更难以知道何时已经完成了所有的组合的计算。

为了解决这个问题，我们必须使用非常类似于我们在`Chapter3-Asynchronous Control Flow Patterns with Callbacks`看到的异步并行执行的模式来追溯`_combine()`方法的所有正在运行的实例。 当`_combine()`方法的所有实例都已经完成运行时，触发`end`事件，通知任何监听器，进程需要做的所有动作都已经完成。

对于最终子集求和算法的重构版本。首先，我们需要将`_combine()`方法中的递归步骤替换为异步：

```javascript
_combine(set, subset) {
  for(let i = 0; i < set.length; i++) {
    let newSubset = subset.concat(set[i]);
    this._combineInterleaved(set.slice(i + 1), newSubset);
    this._processSubset(newSubset);
  }
}
```

通过上面的更改，我们确保算法的每个步骤都将使用`setImmediate()`在事件循环中排队，在事件循环队列中`I / O`请求之后执行，而不是同步运行造成阻塞。

另一个小调整是对于`start()`方法：

```javascript
start() {
  this.runningCombine = 0;
  this._combineInterleaved(this.set, []);
}
```

在前面的代码中，我们将`_combine()`方法的运行实例的数量初始化为`0`.我们还通过调用`_combineInterleaved()`来将调用替换为`_combine()`，并移除了`end`的触发，因为现在`_combineInterleaved()`是异步处理的。
通过这个最后的改变，我们的子集求和算法现在应该能够通过事件循环可以运行的时间间隔交替地运行其可能大量占用`CPU`的代码，并且不会再造成阻塞。

最后更新`app.js`模块，以便它可以使用新版本的`SubsetSum`：

```javascript
const http = require('http');
// const SubsetSum = require('./subsetSum');
const SubsetSum = require('./subsetSumDefer');
http.createServer(function(req, res) {
  // ...
})
```

```javascript
"use strict";

const EventEmitter = require('events').EventEmitter;

class SubsetSumDefer extends EventEmitter {
  constructor(sum, set) {
    super();
    this.sum = sum;
    this.set = set;
    this.totalSubsets = 0;
  }

  /**
   * 增添一个_combineInterleaved方法，把计算过程放到setImmediate异步处理
   * @param  {Array} set
   * @param  {Array} subset
   */
  _combineInterleaved(set, subset) {
    this.runningCombine++;
    setImmediate(() => {
      this._combine(set, subset);
      if(--this.runningCombine === 0) {
        this.emit('end');
      }
    });
  }

  _combine(set, subset) {
    for(let i = 0; i < set.length; i++) {
      let newSubset = subset.concat(set[i]);
      // 替换到setImmediate
      this._combineInterleaved(set.slice(i + 1), newSubset);
      this._processSubset(newSubset);
    }
  }

  _processSubset(subset) {
    console.log('Subset', ++this.totalSubsets, subset);
    const res = subset.reduce((prev, item) => prev + item, 0);
    if(res == this.sum) {
      this.emit('match', subset);
    }
  }

  start() {
    // 设定一个计数器，计数器又归零的时候认为结束计算过���
    this.runningCombine = 0;
    this._combineInterleaved(this.set, []);
  }
}

module.exports = SubsetSumDefer;

```

## 方案二：实现一个进程池
先从构建`processPool.js`模块开始：

```javascript
const fork = require('child_process').fork;
class ProcessPool {
  constructor(file, poolMax) {
      this.file = file;
      this.poolMax = poolMax; // 进程池最大进程数量
      this.pool = []; // 准备运行的进程
      this.active = []; // 正在运行的进程列表，比poolMax数量少
      this.waiting = []; // 任务队列
    } //...
}
```

在模块的第一部分，引入我们将用来创建新进程的`child_process.fork()`函数。 然后，我们定义`ProcessPool`的构造函数，该构造函数接受表示要运行的`Node.js`程序的文件参数以及池中运行的最大实例数`poolMax`作为参数。然后我们定义三个实例变量：

* `pool`表示的是准备运行的进程
* `active`表示的是当前正在运行的进程列表
* `waiting`包含所有这些请求的任务队列，保存由于缺少可用的资源而无法立即实现的任务

看`ProcessPool`类的`acquire()`方法，它负责取出一个准备好被使用的进程：

```javascript
acquire(callback) {
  let worker;
  if(this.pool.length > 0) {  // [1]
    worker = this.pool.pop();
    this.active.push(worker);
    return process.nextTick(callback.bind(null, null, worker));
  }

  if(this.active.length >= this.poolMax) {  // [2]
    return this.waiting.push(callback);
  }

  worker = fork(this.file);  // [3]
  this.active.push(worker);
  process.nextTick(callback.bind(null, null, worker));
}
```

函数逻辑如下：

1. 如果在进程池中有一个准备好被使用的进程，我们只需将其移动到`active`数组中，然后通过异步的方式调用其回调函数。
2. 如果池中没有可用的进程，或者已经达到运行进程的最大数量，必须等待。通过把当前回调放入`waiting`数组。
3. 如果我们还没有达到运行进程的最大数量，我们将使用`child_process.fork()`创建一个新的进程，将其添加到`active`列表中，然后调用其回调。

`ProcessPool`类的最后一个方法是`release()`，其目的是将一个进程放回进程池中：

```javascript
release(worker) {
  if(this.waiting.length > 0) {  // [1]
    const waitingCallback = this.waiting.shift();
    waitingCallback(null, worker);
  }
  this.active = this.active.filter(w => worker !==  w);  // [2]
  this.pool.push(worker);
}
```

前面的代码也很简单，其解释如下：

* 如果在`waiting`任务队列里面有任务需要被执行，我们只需为这个任务分配一个进程`worker`执行。
* 否则，如果在`waiting`任务队列中都没有需要被执行的任务，我们则把`active`的进程列表中的进程放回进程池中。

正如我们所看到的，进程从来没有中断，只在为其不断地重新分配任务，使我们可以通过在每个请求不重新启动一个进程达到节省时间和空间的目的。然而，重要的是要注意，这可能并不总是最好的选择，这很大程度上取决于我们的应用程序的要求。为减少进程池长期占用内存，可能的调整如下：

* 在一个进程空闲一段时间后，终止进程，释放内存空间。
* 添加一个机制来终止或重启没有响应的或者崩溃了的进程。


```javascript
"use strict";

const fork = require('child_process').fork;

class ProcessPool {
  constructor(file, poolMax) {
    this.file = file;
    this.poolMax = poolMax; // 进程池最大进程数量
    this.pool = []; // 准备运行的进程
    this.active = []; // 正在运行的进程列表，比poolMax数量少
    this.waiting = []; // 任务队列
  }

  /**
   * 取出一个进程，然后调用一个任���
   * @param  {Function} callback 
   */
  acquire(callback) {
    let worker;
    if(this.pool.length > 0) {  // 如果进程池中有准备好使用的进程可以取出，那就取出这个进程
      worker = this.pool.pop(); // 取出这个进程
      this.active.push(worker); // 把这个进程放入正在运行的进程列表
      return process.nextTick(callback.bind(null, null, worker)); // 在下一次Tick之前调用它的回调
    }

    if(this.active.length >= this.poolMax) {  // 如果进程池中没有准备好使用的进程，或者已经达到了最大进程运行数量，把这个任务放入等待队列
      return this.waiting.push(callback); // 放入等待队列
    }

    worker = fork(this.file);  // 否则，既不是进程池有进程可以取出，也不是达到最大进程数量，就创建一个进程
    this.active.push(worker); // 把当前进程放入正在运行的进程列表
    process.nextTick(callback.bind(null, null, worker)); // 在下一次Tick之前调用它的回调
  }

  /**
   * 释放正在运行的进程资源，把这个进程放回进程池
   * @param  {Object} worker 表示一个进程
   */
  release(worker) {
    if(this.waiting.length > 0) {  // 如果还有任务等待被执行，先把任务执行完毕
      const waitingCallback = this.waiting.shift(); // 取出等待队列的一个任务
      waitingCallback(null, worker); // 执行这个任务
    }
    this.active = this.active.filter(w => worker !==  w);  // 如果没有任务等待被执行了，则在正在运行的进程列表找到这个进程，并在这个列表删掉它
    this.pool.push(worker); // 并把这个进程放到进程池里
  }
}

module.exports = ProcessPool;

```

